import React, { useState, useEffect } from "react";
import axios from "../api/axios";
import { useNotification } from "../context/NotificationContext";

export default function Profile() {
  const { showNotification } = useNotification();
  const [loading, setLoading] = useState(true);
  const [profile, setProfile] = useState({
    name: "",
    email: "",
    role: "",
    createdAt: "",
    phone: "",
    vehicleNumber: "",
    preferredVehicleType: "Four-wheeler",
  });
  const [isEditing, setIsEditing] = useState(false);

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      const res = await axios.get("/users/me");
      setProfile({
        name: res.data.name || "",
        email: res.data.email || "",
        role: res.data.role || "user",
        createdAt: res.data.createdAt || null,
        phone: res.data.phone || "",
        vehicleNumber: res.data.vehicleNumber || "",
        preferredVehicleType: res.data.preferredVehicleType || "Four-wheeler",
      });
      setLoading(false);
    } catch (error) {
      console.error("Profile Fetch Error:", error);
      showNotification("error", "Failed to load profile parameters.");
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    setProfile({ ...profile, [e.target.name]: e.target.value });
  };

  const handleSave = async (e) => {
    e.preventDefault();
    try {
      await axios.put("/users/me", {
        name: profile.name,
        phone: profile.phone,
        vehicleNumber: profile.vehicleNumber,
        preferredVehicleType: profile.preferredVehicleType,
      });
      showNotification("success", "Profile updated successfully!");
      setIsEditing(false);
    } catch (error) {
      showNotification("error", "Failed to save profile changes.");
    }
  };

  if (loading) return <div style={{ padding: "24px" }}>Loading Profile...</div>;

  return (
    <div style={{ padding: "24px", maxWidth: "800px" }}>
      <h2 style={{ marginBottom: "24px", color: "var(--text-primary)" }}>My Profile</h2>

      <div style={{ background: "var(--bg-secondary)", padding: "24px", borderRadius: "var(--radius-md)", border: "1px solid var(--border-subtle)", boxShadow: "var(--shadow-sm)" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "24px" }}>
          <div style={{ display: "flex", gap: "16px", alignItems: "center" }}>
            <div style={{ width: "64px", height: "64px", borderRadius: "50%", background: "linear-gradient(135deg, var(--accent-primary), var(--accent-secondary))", color: "white", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "1.8rem", fontWeight: "bold" }}>
              {profile.name ? profile.name.charAt(0).toUpperCase() : "U"}
            </div>
            <div>
              <h3 style={{ margin: "0 0 4px 0", color: "var(--text-primary)" }}>{profile.name}</h3>
              <div style={{ color: "var(--text-secondary)", fontSize: "0.9rem" }}>{profile.email}</div>
              <div style={{ display: "inline-block", marginTop: "8px", background: "rgba(37,99,235,0.1)", color: "var(--accent-primary)", padding: "4px 8px", borderRadius: "4px", fontSize: "0.75rem", fontWeight: "bold", textTransform: "uppercase" }}>
                {profile.role === "admin" ? "Admin" : profile.role === "parkingLotAdmin" ? "Lot Admin" : "Standard User"}
              </div>
            </div>
          </div>
          <div>
            {!isEditing ? (
              <button 
                onClick={() => setIsEditing(true)} 
                style={{ background: "white", border: "1px solid var(--border-subtle)", padding: "8px 16px", borderRadius: "var(--radius-sm)", cursor: "pointer", fontSize: "0.9rem", color: "var(--text-primary)", fontWeight: "500", transition: "all 0.2s" }}
              >
                <i className="fa-solid fa-pen" style={{ marginRight: "6px" }}></i> Edit Profile
              </button>
            ) : null}
          </div>
        </div>

        <form onSubmit={handleSave}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "20px", marginBottom: "24px" }}>

            {/* General Info */}
            <div style={{ gridColumn: "1 / -1", borderBottom: "1px solid var(--border-subtle)", paddingBottom: "12px", marginTop: "12px" }}>
              <strong style={{ color: "var(--text-primary)" }}>Personal Information</strong>
            </div>

            <div>
              <label style={{ display: "block", marginBottom: "8px", fontSize: "0.9rem", color: "var(--text-secondary)" }}>Full Name</label>
              <input 
                type="text" 
                name="name" 
                value={profile.name} 
                onChange={handleChange} 
                disabled={!isEditing}
                style={{ width: "100%", padding: "10px", borderRadius: "var(--radius-sm)", border: "1px solid var(--border-subtle)", background: isEditing ? "white" : "var(--bg-primary)", color: "var(--text-primary)", outline: "none" }}
              />
            </div>

            <div>
              <label style={{ display: "block", marginBottom: "8px", fontSize: "0.9rem", color: "var(--text-secondary)" }}>Email Address <span style={{ fontSize: "0.75rem", color: "var(--status-danger)", marginLeft: "4px" }}>(Read Only)</span></label>
              <input 
                type="email" 
                value={profile.email} 
                disabled 
                style={{ width: "100%", padding: "10px", borderRadius: "var(--radius-sm)", border: "1px solid var(--border-subtle)", background: "var(--bg-primary)", color: "var(--text-muted)", outline: "none", cursor: "not-allowed" }}
              />
            </div>

            <div>
              <label style={{ display: "block", marginBottom: "8px", fontSize: "0.9rem", color: "var(--text-secondary)" }}>Phone Number</label>
              <input 
                type="text" 
                name="phone" 
                value={profile.phone} 
                onChange={handleChange} 
                disabled={!isEditing}
                placeholder="Optional"
                style={{ width: "100%", padding: "10px", borderRadius: "var(--radius-sm)", border: "1px solid var(--border-subtle)", background: isEditing ? "white" : "var(--bg-primary)", color: "var(--text-primary)", outline: "none" }}
              />
            </div>

            <div>
              <label style={{ display: "block", marginBottom: "8px", fontSize: "0.9rem", color: "var(--text-secondary)" }}>Account Created</label>
              <div style={{ padding: "10px", background: "var(--bg-primary)", borderRadius: "var(--radius-sm)", border: "1px solid var(--border-subtle)", color: "var(--text-muted)", fontSize: "0.95rem" }}>
                {profile.createdAt ? new Date(profile.createdAt).toLocaleDateString() : "N/A"}
              </div>
            </div>

            {/* Parking Defaults */}
            <div style={{ gridColumn: "1 / -1", borderBottom: "1px solid var(--border-subtle)", paddingBottom: "12px", marginTop: "12px" }}>
              <strong style={{ color: "var(--text-primary)" }}>Vehicle Information</strong>
            </div>

            <div>
              <label style={{ display: "block", marginBottom: "8px", fontSize: "0.9rem", color: "var(--text-secondary)" }}>Primary Vehicle Number</label>
              <input 
                type="text" 
                name="vehicleNumber" 
                value={profile.vehicleNumber} 
                onChange={handleChange} 
                disabled={!isEditing}
                placeholder="e.g., TN 45 XX 1234"
                style={{ width: "100%", padding: "10px", borderRadius: "var(--radius-sm)", border: "1px solid var(--border-subtle)", background: isEditing ? "white" : "var(--bg-primary)", color: "var(--text-primary)", outline: "none" }}
              />
            </div>

            <div>
              <label style={{ display: "block", marginBottom: "8px", fontSize: "0.9rem", color: "var(--text-secondary)" }}>Preferred Vehicle Type</label>
              <select 
                name="preferredVehicleType" 
                value={profile.preferredVehicleType} 
                onChange={handleChange} 
                disabled={!isEditing}
                style={{ width: "100%", padding: "10px", borderRadius: "var(--radius-sm)", border: "1px solid var(--border-subtle)", background: isEditing ? "white" : "var(--bg-primary)", color: "var(--text-primary)", outline: "none" }}
              >
                <option value="Four-wheeler">Four-wheeler (Car)</option>
                <option value="Two-wheeler">Two-wheeler (Bike)</option>
              </select>
            </div>

          </div>

          {isEditing && (
            <div style={{ display: "flex", gap: "12px", justifyContent: "flex-end", marginTop: "32px", borderTop: "1px solid var(--border-subtle)", paddingTop: "20px" }}>
              <button 
                type="button" 
                onClick={() => { setIsEditing(false); fetchProfile(); }} 
                style={{ background: "white", border: "1px solid var(--border-subtle)", padding: "10px 24px", borderRadius: "var(--radius-sm)", cursor: "pointer", fontWeight: "600", color: "var(--text-secondary)" }}
              >
                Cancel
              </button>
              <button 
                type="submit" 
                style={{ background: "var(--accent-primary)", border: "none", color: "white", padding: "10px 32px", borderRadius: "var(--radius-sm)", cursor: "pointer", fontWeight: "600", transition: "background 0.2s" }}
              >
                Save Changes
              </button>
            </div>
          )}
        </form>

      </div>
    </div>
  );
}
